const { chromium } = require('playwright');

(async () => {
  const browser = await chromium.launch({ headless: false });
  const page = await browser.newPage();
  await page.goto('https://www.amazon.in/s?k=iPhone+6s');
  await page.waitForTimeout(5000);

  const prices = await page.$$eval('.a-price .a-offscreen', els => 
    els.map(e => e.textContent.trim()).slice(0, 5)
  );

  const titles = await page.$$eval('[data-component-type="s-search-result"] h2 a span', els =>
    els.map(e => e.textContent.trim()).slice(0, 5)
  );

  console.log(JSON.stringify({ titles, prices }, null, 2));
  await browser.close();
})();

