const { chromium } = require('playwright');

(async () => {
  const browser = await chromium.launch({ 
    headless: false,
    args: ['--disable-blink-features=AutomationControlled']
  });
  const context = await browser.newContext({
    userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
    viewport: { width: 1366, height: 768 }
  });
  const page = await context.newPage();

  await page.addInitScript(() => {
    Object.defineProperty(navigator, 'webdriver', { get: () => undefined });
  });

  await page.goto('https://www.amazon.in');
  await page.waitForTimeout(3000);

  await page.fill('#twotabsearchtextbox', 'iPhone 6s');
  await page.press('#twotabsearchtextbox', 'Enter');
  await page.waitForTimeout(5000);

  // Try multiple title selectors
  const results = await page.$$eval('[data-component-type="s-search-result"]', items =>
    items.slice(0, 8).map((item, idx) => {
      // Try various title selectors
      const titleSelectors = [
        'h2 a span',
        'h2 span',
        '.a-size-mini span',
        '.a-size-base-plus',
        'h2 a',
        '[data-cy="title-recipe-title"]',
        '.s-size-mini span',
        '.a-link-normal .a-text-normal'
      ];

      let title = 'No title';
      for (const sel of titleSelectors) {
        const el = item.querySelector(sel);
        if (el && el.textContent.trim()) {
          title = el.textContent.trim();
          break;
        }
      }

      const priceEl = item.querySelector('.a-price .a-offscreen');
      const wholeEl = item.querySelector('.a-price-whole');
      const price = priceEl ? priceEl.textContent.trim() : (wholeEl ? '₹' + wholeEl.textContent.trim() : 'No price');

      return { idx: idx + 1, title, price };
    })
  );

  // Also get page HTML around search results for debugging
  const htmlSnippet = await page.$eval('[data-component-type="s-search-result"]', el => el.outerHTML.substring(0, 500)).catch(() => 'No results found');

  console.log(JSON.stringify(results, null, 2));
  console.log('\n--- HTML snippet ---');
  console.log(htmlSnippet);

  await browser.close();
})();

