      const titleEl = item.querySelector('a[title]') || item.querySelector('.KzDlHZ') || item.querySelector('._4rR01T');
      const priceEl = item.querySelector('.Nx9bqj') || item.querySelector('._30jeq3');
      const origPriceEl = item.querySelector('.yRaY8j') || item.querySelector('._27UcVY');

      return {
        idx: idx + 1,
        title: titleEl ? (titleEl.getAttribute('title') || titleEl.textContent.trim()) : 'No title',
        price: priceEl ? priceEl.textContent.trim() : 'No price',
        originalPrice: origPriceEl ? origPriceEl.textContent.trim() : null
      };
    }).filter(r => r.price !== 'No price' && r.title.toLowerCase().includes('iphone'))
  );

  console.log(JSON.stringify(flipkartResults, null, 2));

  // Also try Amazon for iPhone 16
  console.log('\n=== AMAZON.IN: iPhone 16 ===');
  await page.goto('https://www.amazon.in/s?k=iPhone+16');
  await page.waitForTimeout(6000);

  await page.evaluate(() => window.scrollBy(0, 800));
  await page.waitForTimeout(2000);

  const amazonResults = await page.$$eval('[data-component-type="s-search-result"]', items => 
    items.slice(0, 6).map((item, idx) => {
      const titleSelectors = [
        'h2 a span', 'h2 span', '.a-size-mini span', '.a-size-base-plus', 'h2 a'
      ];

      let title = 'No title';
      for (const sel of titleSelectors) {
        const el = item.querySelector(sel);
        if (el && el.textContent.trim()) {
          title = el.textContent.trim();
          break;
        }
      }

      const priceEl = item.querySelector('.a-price .a-offscreen');
      const wholeEl = item.querySelector('.a-price-whole');
      const price = priceEl ? priceEl.textContent.trim() : (wholeEl ? '₹' + wholeEl.textContent.trim() : 'No price');

      return { idx: idx + 1, title, price };
    }).filter(r => r.price !== 'No price' && /iphone 16/i.test(r.title))
  );

  console.log(JSON.stringify(amazonResults, null, 2));

  await browser.close();
})();

