const { chromium } = require('playwright');

(async () => {
  const browser = await chromium.launch({ 
    headless: false,
    args: ['--disable-blink-features=AutomationControlled']
  });
  const context = await browser.newContext({
    userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
    viewport: { width: 1366, height: 768 }
  });
  const page = await context.newPage();

  await page.addInitScript(() => {
    Object.defineProperty(navigator, 'webdriver', { get: () => undefined });
  });

  // Try Flipkart
  console.log('=== FLIPKART: iPhone 16 ===');
  await page.goto('https://www.flipkart.com/search?q=iphone+16', { waitUntil: 'networkidle' });
  await page.waitForTimeout(3000);

  // Save screenshot for debugging
  await page.screenshot({ path: 'C:\\Users\\91733\\.openclaw\\workspace\\flipkart_iphone16.png', fullPage: false });

  // Try broader selectors for Flipkart
  const flipkartResults = await page.$$eval('._1AtVbE, .slAVV4, [data-id]', items => 
    items.slice(0, 8).map((item, idx) => {
      // Try multiple selectors for title
      const titleEl = item.querySelector('._4rR01T') || item.querySelector('.KzDlHZ') || 
                       item.querySelector('a[title]') || item.querySelector('._1fQZEK') ||
                       item.querySelector('a[rel="noopener noreferrer"]');

      // Try multiple selectors for price
      const priceEl = item.querySelector('._30jeq3') || item.querySelector('.Nx9bqj') ||
                       item.querySelector('._1_WHN1') || item.querySelector('._3I9_wc');

      const title = titleEl ? (titleEl.getAttribute('title') || titleEl.textContent.trim()) : 'No title';
      const price = priceEl ? priceEl.textContent.trim() : 'No price';

      return { idx: idx + 1, title, price };
    }).filter(r => r.price !== 'No price' && r.title.length > 5)
  );

  console.log('Flipkart results found:', flipkartResults.length);
  console.log(JSON.stringify(flipkartResults.slice(0, 5), null, 2));

  // Try Amazon
  console.log('\n=== AMAZON.IN: iPhone 16 ===');
  await page.goto('https://www.amazon.in/s?k=iPhone+16', { waitUntil: 'networkidle' });
  await page.waitForTimeout(3000);

  await page.screenshot({ path: 'C:\\Users\\91733\\.openclaw\\workspace\\amazon_iphone16.png', fullPage: false });

  const amazonResults = await page.$$eval('[data-component-type="s-search-result"]', items => 
    items.slice(0, 8).map((item, idx) => {
      const titleSelectors = [
        'h2 a span', 'h2 span', '.a-size-mini span', '.a-size-base-plus', 
        'h2 a', '.a-link-normal .a-text-normal', '.a-size-base.a-color-base'
      ];

      let title = 'No title';
      for (const sel of titleSelectors) {
        const el = item.querySelector(sel);
        if (el && el.textContent.trim()) {
          title = el.textContent.trim();
          break;
        }
      }

      const priceEl = item.querySelector('.a-price .a-offscreen');
      const wholeEl = item.querySelector('.a-price-whole');
      const price = priceEl ? priceEl.textContent.trim() : (wholeEl ? '₹' + wholeEl.textContent.trim() : 'No price');

      return { idx: idx + 1, title, price };
    }).filter(r => r.price !== 'No price' && r.title.length > 5)
  );

  console.log('Amazon results found:', amazonResults.length);
  console.log(JSON.stringify(amazonResults.slice(0, 5), null, 2));

  await browser.close();
})();

